using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

namespace TicketClassifier.Models;

public class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public static string TrainAndSave(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split for evaluation (80/20)
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: featurize text columns, combine with Priority, then classify
        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train
        logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var report = FormatMetrics(metrics);
        logger.LogInformation("Model evaluation metrics:\n{Metrics}", report);

        // Save model
        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {Path}", modelPath);

        return report;
    }

    private static string FormatMetrics(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics)
    {
        return $"""
            ╔════════════════════════════════════════════╗
            ║     Ticket Classifier — Evaluation         ║
            ╠════════════════════════════════════════════╣
            ║  Macro Accuracy:  {metrics.MacroAccuracy:F4}                 ║
            ║  Micro Accuracy:  {metrics.MicroAccuracy:F4}                 ║
            ║  Log Loss:        {metrics.LogLoss:F4}                 ║
            ║  Log Loss (red.): {metrics.LogLossReduction:F4}                 ║
            ╚════════════════════════════════════════════╝

            Per-class log loss:
            {string.Join("\n", metrics.PerClassLogLoss.Select((v, i) =>
                $"  [{i}] {CategoryLabels.ElementAtOrDefault(i) ?? $"Class {i}"}: {v:F4}"))}

            Confusion matrix:
            {metrics.ConfusionMatrix.GetFormattedConfusionTable()}
            """;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
    ILogger<TicketClassifierController> logger) : ControllerBase
{
    private static readonly string[] Labels = ["Billing", "General", "Technical"];

    [HttpPost("predict")]
    public ActionResult<TicketClassificationResult> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < Labels.Length; i++)
            confidence[Labels[i]] = prediction.Score[i];

        logger.LogInformation("Predicted {Category} for ticket \"{Subject}\"",
            prediction.PredictedCategory, request.Subject);

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        });
    }
}

