namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ILogger<TicketClassifierController> _logger;
    private readonly string[] _labels;

    public TicketClassifierController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ILogger<TicketClassifierController> logger)
    {
        _predictionPool = predictionPool;
        _logger = logger;

        // Extract label names from the model's Score column slot metadata
        var engine = predictionPool.GetPredictionEngine();
        var schema = engine.OutputSchema;
        var scoreColumn = schema.GetColumnOrNull("Score")
            ?? throw new InvalidOperationException("Score column not found in model output schema.");
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.Value.GetSlotNames(ref slotNames);
        _labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    [HttpPost("predict")]
    public ActionResult<TicketClassificationResult> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < _labels.Length; i++)
            confidence[_labels[i]] = prediction.Score[i];

        _logger.LogInformation("Predicted {Category} for ticket \"{Subject}\"",
            prediction.PredictedCategory, request.Subject);

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        });
    }
}

