 using Microsoft.Extensions.ML;
 using TicketClassifier.Models;
 using TicketClassifier.Services;

 var builder = WebApplication.CreateBuilder(args);
 builder.Services.AddControllers();

 // Paths for training data and saved model
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ticket_model.zip");

 // Train the model at startup and log evaluation metrics
 using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
 var metrics = TicketModelTrainer.TrainAndSave(dataPath, modelPath,
     loggerFactory.CreateLogger("TicketClassifier.Startup"));

 // Register the thread-safe PredictionEnginePool
 builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();
 app.MapControllers();

 // Surface metrics at GET /api/ticketclassifier/metrics
 app.MapGet("/api/ticketclassifier/metrics", () => Results.Text(metrics, "text/plain"));

 app.Run();
